#nullable enable // autogenerated

using MVZ2.GameContent.Entities;
using MVZ2.GameContent.Projectiles;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using MVZ2.Vanilla.StateMachine;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.brickCannon)]
    public class BrickCannon : AIEntityBehaviour
    {
        public BrickCannon(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetNoMissile(entity, true);

            stateMachine.Init(entity);
            stateMachine.StartState(entity, STATE_IDLE);
            var timer = stateMachine.GetStateTimer(entity);
            timer.SetSeconds(START_RELOAD_TIME_SECONDS);
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            stateMachine.UpdateAI(entity);
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            stateMachine.UpdateLogic(entity);

            var animationSpeed = entity.IsAIFrozen() ? 0 : 1;
            entity.SetModelProperty("NoMissile", HasNoMissile(entity));
            entity.SetAnimationBool("Danger", IsDanger(entity));
            entity.SetAnimationInt("BodyState", GetAnimationBodyState(entity));
            entity.SetAnimationFloat("AnimationSpeed", animationSpeed);
            entity.SetAnimationFloat("AnimationAttackSpeed", animationSpeed * entity.GetAttackSpeed());
        }
        public int GetAnimationBodyState(Entity entity)
        {
            switch (entity.State)
            {
                case STATE_RELOAD:
                    return 1;
                case STATE_LAUNCH:
                    return 2;
            }
            return 0;
        }
        public static void Launch(Entity entity, Vector3 target)
        {
            stateMachine.StartState(entity, STATE_LAUNCH);
            SetTargetPosition(entity, target);
        }
        public static void ReloadImmediate(Entity entity)
        {
            if (!HasNoMissile(entity) || entity.State != STATE_IDLE)
                return;
            var timer = stateMachine.GetStateTimer(entity);
            timer.SetSeconds(0);
        }
        public static bool IsDanger(Entity entity) => entity.GetProperty<bool>(PROP_DANGER);
        public static void SetDanger(Entity entity, bool value) => entity.SetProperty(PROP_DANGER, value);
        public static bool HasNoMissile(Entity entity) => entity.GetProperty<bool>(PROP_NO_MISSILE);
        public static void SetNoMissile(Entity entity, bool value) => entity.SetProperty(PROP_NO_MISSILE, value);
        public static Vector3 GetTargetPosition(Entity entity) => entity.GetProperty<Vector3>(PROP_TARGET_POSITION);
        public static void SetTargetPosition(Entity entity, Vector3 value) => entity.SetProperty(PROP_TARGET_POSITION, value);
        public const int STATE_IDLE = VanillaContraptionStates.IDLE;
        public const int STATE_RELOAD = VanillaContraptionStates.BRICK_CANNON_RELOAD;
        public const int STATE_LAUNCH = VanillaContraptionStates.BRICK_CANNON_LAUNCH;
        public const float START_RELOAD_TIME_SECONDS = 5;
        public static readonly VanillaEntityPropertyMeta<bool> PROP_DANGER = new VanillaEntityPropertyMeta<bool>("danger");
        public static readonly VanillaEntityPropertyMeta<bool> PROP_NO_MISSILE = new VanillaEntityPropertyMeta<bool>("no_missile");
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_TARGET_POSITION = new VanillaEntityPropertyMeta<Vector3>("target_position");
        private static EntityStateMachine stateMachine = new BrickCannonStateMachine();
        private class BrickCannonStateMachine : EntityStateMachine
        {
            public BrickCannonStateMachine()
            {
                AddState(new IdleState());
                AddState(new ReloadState());
                AddState(new LaunchState());
            }
        }
        private class IdleState : EntityStateMachineState
        {
            public IdleState() : base(STATE_IDLE)
            {
            }

            public override void OnEnter(EntityStateMachine machine, Entity entity)
            {
                base.OnEnter(machine, entity);
                var stateTimer = machine.GetStateTimer(entity);
                stateTimer.ResetSeconds(RELOAD_TIME_SECONDS);
            }

            public override void OnUpdateAI(EntityStateMachine machine, Entity entity)
            {
                base.OnUpdateAI(machine, entity);
                if (!HasNoMissile(entity))
                    return;
                var timer = machine.GetStateTimer(entity);
                if (timer.RunToExpired(entity.GetAttackSpeed()))
                {
                    machine.StartState(entity, STATE_RELOAD);
                }
            }
            public const float RELOAD_TIME_SECONDS = 30;
        }
        private class ReloadState : EntityStateMachineState
        {
            public ReloadState() : base(STATE_RELOAD)
            {
            }

            public override void OnEnter(EntityStateMachine machine, Entity entity)
            {
                base.OnEnter(machine, entity);
                var substateTimer = machine.GetSubStateTimer(entity);
                substateTimer.ResetSeconds(POP_TIME_SECONDS);
            }

            public override void OnUpdateAI(EntityStateMachine machine, Entity entity)
            {
                base.OnUpdateAI(machine, entity);
                var substateTimer = machine.GetSubStateTimer(entity);
                var substate = machine.GetSubState(entity);
                switch (substate)
                {
                    case SUBSTATE_START:
                        if (substateTimer.RunToExpired(entity.GetAttackSpeed()))
                        {
                            entity.PlaySound(VanillaSoundID.gunReload, 0.75f);
                            SetNoMissile(entity, false);
                            machine.StartSubState(entity, SUBSTATE_POP);
                            substateTimer.ResetSeconds(FINISH_TIME_SECONDS);
                        }
                        break;
                    case SUBSTATE_POP:
                        if (substateTimer.RunToExpired(entity.GetAttackSpeed()))
                        {
                            machine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const float POP_TIME_SECONDS = 1;
            public const float FINISH_TIME_SECONDS = 0.5f;
            public const int SUBSTATE_START = 0;
            public const int SUBSTATE_POP = 1;

        }
        private class LaunchState : EntityStateMachineState
        {
            public LaunchState() : base(STATE_LAUNCH)
            {
            }

            public override void OnEnter(EntityStateMachine machine, Entity entity)
            {
                base.OnEnter(machine, entity);
                var substateTimer = machine.GetSubStateTimer(entity);
                substateTimer.ResetSeconds(LAUNCH_TIME_SECONDS);
            }

            public override void OnUpdateAI(EntityStateMachine machine, Entity entity)
            {
                base.OnUpdateAI(machine, entity);
                var substateTimer = machine.GetSubStateTimer(entity);
                var substate = machine.GetSubState(entity);
                switch (substate)
                {
                    case SUBSTATE_START:
                        if (substateTimer.RunToExpired(entity.GetAttackSpeed()))
                        {
                            LaunchMissile(entity);
                            SetNoMissile(entity, true);
                            SetDanger(entity, false);
                            machine.StartSubState(entity, SUBSTATE_LAUNCHED);
                            substateTimer.ResetSeconds(FINISH_TIME_SECONDS);
                        }
                        break;
                    case SUBSTATE_LAUNCHED:
                        if (substateTimer.RunToExpired(entity.GetAttackSpeed()))
                        {
                            machine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public Entity? LaunchMissile(Entity entity)
            {
                var danger = IsDanger(entity);
                var param = entity.GetShootParams();
                param.spawnParam.SetProperty(CannonMissile.PROP_TARGET_POSITION, GetTargetPosition(entity));
                param.spawnParam.SetProperty(LogicEntityProps.VARIANT, danger ? CannonMissile.VARIANT_DANGER : CannonMissile.VARIANT_NORMAL);
                return entity.ShootProjectile(param);
            }
            public const float LAUNCH_TIME_SECONDS = 1.333333333f;
            public const float FINISH_TIME_SECONDS = 1f;
            public const int SUBSTATE_START = 0;
            public const int SUBSTATE_LAUNCHED = 1;
        }
    }
}
